bool ModelManager::processData()
{
	bool repeat = true;

	nodeBuff.push_back(modelScene->mRootNode);
	

	/* if (modelScene->mNumMeshes > 0)
	{
	for (unsigned int m=0;m<modelScene->mNumMeshes;m++)
	this->assimpGetMeshData(modelScene->mMeshes[m]);
